#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct {
  float weight;
  long assign;
  float cost;
} Point_Struct;

kernel void pgain_kernel(
    global const Point_Struct* p,
    global const float* coord,
    global float* work_mem,
    global const int* center_table,
    global char* switch_membership,
    local float* local_coord,
    int num,
    int dim,
    long x,
    int K)
{
    int i = get_global_id(0);
    if (i >= num) return;

    int tid = get_local_id(0);
    int stride = get_local_size(0);

    // Load center coordinates into local memory
    // Ensure we don't access beyond local memory size if dim is large
    for (int d = tid; d < dim; d += stride) {
        local_coord[d] = coord[x * dim + d];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    // Calculate distance to new center x
    float x_cost = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[i * dim + d] - local_coord[d];
        x_cost += diff * diff;
    }
    x_cost *= p[i].weight;

    float current_cost = p[i].cost;

    if (x_cost < current_cost) {
        switch_membership[i] = (char)1;
        // Accumulate cost difference in the last column (index K) of row i
        // work_mem layout: [num rows] x [K+1 columns]
        // Row i starts at i * (K + 1)
        work_mem[i * (K + 1) + K] += (x_cost - current_cost);
    } else {
        int assign = (int)p[i].assign;
        int ct = center_table[assign];
        // Accumulate savings in the column corresponding to the current center
        if (ct >= 0 && ct < K) {
            work_mem[i * (K + 1) + ct] += (current_cost - x_cost);
        }
    }
}
